// Column mapping configuration
// Note: Run Google Workspace Initialization workflow first to create the spreadsheet
// Then configure the sheetId in the "Read Google Sheet" node
const mapping = {
  company_name: "Company Name",
  company_website: "Company Website",
  first_name: "First Name",
  last_name: "Last Name",
  email: "Email",
  phone: "Phone",
  mobile: "Mobile",
  title: "Title",
  source: "Source",
  estimated_value: "Estimated Value",
  last_modified: "Last Modified",
  status: "Status",
  priority_score: "Priority Score",
  next_followup_at: "Next Follow-up",
  days_overdue: "Days Overdue"
};

// Apply mapping to each row
const mappedRows = [];
for (const item of $input.all()) {
  const row = item.json;
  const mapped = {};

  for (const [key, sheetColumn] of Object.entries(mapping)) {
    mapped[key] = row[sheetColumn] || null;
  }

  // Set default source if not provided
  if (!mapped.source) {
    mapped.source = "google_sheets";
  }

  mappedRows.push(mapped);
}

return mappedRows;

// Prepare batch import request
const rows = $input.all();
const leads = rows.map(row => row.json);

return [{
  json: {
    leads: leads,
    source: "google_sheets"
  }
}];

const response = $input.item.json;

if (response.success && response.data) {
  return [{
    json: {
      success: true,
      imported: response.data.imported,
      updated: response.data.updated,
      failed: response.data.failed,
      errors: response.data.errors || [],
      message: response.message
    }
  }];
} else {
  return [{
    json: {
      success: false,
      imported: 0,
      updated: 0,
      failed: 0,
      errors: response.errors || [response.message],
      message: response.message
    }
  }];
}
